import { Legend } from "chart.js";
import React from "react";
import { Bar } from 'react-chartjs-2';
import { COLORS } from "../config/config_chart";
import { getStatistics } from "../utility/function";

const Chart = (props) => {
    let label = props.categoriesStatus === "no" ? "products" : "categories";
    const maxVisitedOfClient = getStatistics(prop.orders);

    let database = { labels: [], data: [], label: label + " statistic in a chart" }

    for (let entry of maxVisitedOfClient) {
        database.labels.push(entry[0]);
        database.data.push(entry[1].count);
    }

    const data = {
        labels: database.labels,
        datasets: [{
            label: database.label,
            data: database.data,
            backgroundColor: [...COLORS]
        }]
    };

    return <React.Fragment>
        <div className="chart-wrapper">
            <Bar
                className="chart"
                data={data}
                width={100}
                height={50}
                options={{maintainAspectRatio: true,}}
            />
        </div>
    </React.Fragment>
}

export default Chart;
